import{_ as t,o as a,c as i,a2 as s}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"Faction system","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faction-system.md","filePath":"guide/faction-system.md","lastUpdated":1782023680000}'),o={name:"guide/faction-system.md"};function d(n,e,r,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="faction-system" tabindex="-1">Faction system <a class="header-anchor" href="#faction-system" aria-label="Permalink to &quot;Faction system&quot;">​</a></h1><p>E4.1 adds the faction foundation: stable data, pure reputation helpers, a friend/foe matrix, and a Redux slice that exposes player faction state. E4.2 builds on it with the New-Game <strong>faction picker</strong>, <strong>asymmetric per-faction objectives</strong>, and <strong>save persistence</strong> of the chosen faction. Soldier AI, caravan AI, and objective-driven behaviour still belong to later tickets — the objective data here is declarative and not yet wired into the live sim.</p><h2 id="stable-ids" tabindex="-1">Stable ids <a class="header-anchor" href="#stable-ids" aria-label="Permalink to &quot;Stable ids&quot;">​</a></h2><p>Faction ids are schema-facing strings. Do not rename them after they ship:</p><table tabindex="0"><thead><tr><th>Key</th><th>Id</th><th>Role</th></tr></thead><tbody><tr><td><code>Neutral</code></td><td><code>neutral</code></td><td>Human lands, unaffiliated locals, and ordinary caravans</td></tr><tr><td><code>Empire</code></td><td><code>empire</code></td><td>Empire / Palace Guard forces</td></tr><tr><td><code>ForestElves</code></td><td><code>forestElves</code></td><td>Elven wardens and forest defenders</td></tr><tr><td><code>Villain</code></td><td><code>villain</code></td><td>Hostile dark-aligned forces</td></tr></tbody></table><p>Definitions live in <code>src/game/faction/</code> as <code>FACTIONS</code>, <code>FACTION_IDS</code>, and <code>FACTION_ID_LIST</code>. Display names, descriptions, and home-region text can change; ids should not.</p><h2 id="stance-matrix" tabindex="-1">Stance matrix <a class="header-anchor" href="#stance-matrix" aria-label="Permalink to &quot;Stance matrix&quot;">​</a></h2><p><code>resolveStance(a, b)</code> returns one of <code>hostile | neutral | allied</code> from the static relationship matrix. The matrix is deliberately symmetric and deterministic:</p><table tabindex="0"><thead><tr><th>A / B</th><th>Neutral</th><th>Empire</th><th>Forest Elves</th><th>Villain</th></tr></thead><tbody><tr><td>Neutral</td><td>allied</td><td>neutral</td><td>neutral</td><td>hostile</td></tr><tr><td>Empire</td><td>neutral</td><td>allied</td><td>hostile</td><td>hostile</td></tr><tr><td>Forest Elves</td><td>neutral</td><td>hostile</td><td>allied</td><td>hostile</td></tr><tr><td>Villain</td><td>hostile</td><td>hostile</td><td>hostile</td><td>allied</td></tr></tbody></table><p>Use this for faction-to-faction defaults. Do not infer player-specific stance from this matrix until the AI integration tickets define that rule.</p><h2 id="reputation" tabindex="-1">Reputation <a class="header-anchor" href="#reputation" aria-label="Permalink to &quot;Reputation&quot;">​</a></h2><p>Player reputation is a serialisable <code>FactionId -&gt; number</code> map. Values are clamped to <code>-100..100</code>; non-finite values normalise to <code>0</code>; fractional inputs are truncated. Defaults are neutral with the settled factions and hostile with the villain faction:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  neutral</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  empire</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  forestElves</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  villain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">75</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Use <code>setReputation</code> and <code>adjustReputation</code> from <code>src/game/faction/</code> for pure updates. They return fresh maps and never mutate the input.</p><h2 id="store-bridge" tabindex="-1">Store bridge <a class="header-anchor" href="#store-bridge" aria-label="Permalink to &quot;Store bridge&quot;">​</a></h2><p><code>src/store/factionSlice.ts</code> keeps the current player faction and reputation map in Redux:</p><ul><li><code>setPlayerFaction(id)</code></li><li><code>setFactionReputation({ factionId, value })</code></li><li><code>adjustFactionReputation({ factionId, amount })</code></li><li><code>resetFaction()</code></li><li><code>restoreFaction(state)</code></li><li>selectors for current faction id, current faction definition, a single reputation value, and the full reputation map</li></ul><p>The slice delegates bounds and map updates to the pure model. Reputation is not yet part of the save schema; only the chosen player faction is persisted (see <strong>Save persistence</strong> below).</p><h2 id="playable-factions-selection-e4-2" tabindex="-1">Playable factions &amp; selection (E4.2) <a class="header-anchor" href="#playable-factions-selection-e4-2" aria-label="Permalink to &quot;Playable factions &amp; selection (E4.2)&quot;">​</a></h2><p>Three of the four factions are player-selectable; <code>neutral</code> is the unaffiliated default the player carries until (and unless) they choose. The selectable set, in picker order, is <code>PLAYABLE_FACTION_IDS</code> = <code>[forestElves, empire, villain]</code>.</p><ul><li><code>isFactionId(value)</code> / <code>isPlayableFactionId(value)</code> — type guards used by save migration to validate an untrusted faction id (an unknown id falls back to <code>neutral</code> rather than corrupting state).</li><li><code>PLAYABLE_FACTIONS</code> — a picker-ready list merging each faction&#39;s identity with its playbook (name, home, role, tagline, objectives).</li></ul><p>The New-Game flow lives in <code>src/app/App.tsx</code>: <strong>New Game</strong> opens the <code>FactionPicker</code> overlay (<code>src/components/FactionPicker.tsx</code>) instead of starting immediately. The picker is a two-step select→confirm affordance with empty, loading, and selected states. Choosing a faction and pressing <strong>Begin</strong> dispatches <code>setPlayerFaction(id)</code> (alongside the player/health/inventory resets) and then <code>startNewGame()</code>.</p><p>Visual polish from Iris&#39;s E4.2 review (FLO-370): the selected card carries a 2px gold inset ring plus a gold ✓ badge — a colour-independent cue (WCAG 1.4.1) distinct from hover — and <strong>Begin</strong> uses the shared <code>button.primary-action</code> treatment (gold fill, dark ink) so the commit action reads as primary against the neutral <strong>Clear</strong>/<strong>Back</strong> controls. <code>.primary-action</code> is the one app-wide primary-CTA primitive (also used by New Game, endgame Restart, WorldMap Travel, and the Onboarding CTA); it is defined once in <code>src/styles/global.css</code>.</p><h2 id="asymmetric-objectives-e4-2" tabindex="-1">Asymmetric objectives (E4.2) <a class="header-anchor" href="#asymmetric-objectives-e4-2" aria-label="Permalink to &quot;Asymmetric objectives (E4.2)&quot;">​</a></h2><p>Each playable faction has a typed <strong>playbook</strong> in <code>src/game/faction/objectives.ts</code> describing its asymmetric goals. The data is declarative — it states intent (raid whom, defend where) and is consumed by later tickets (commander/order system, AI targeting, quest tracking); it does not drive behaviour yet. Objective <code>id</code>s are stable strings (quest tracking will point at them) — treat them like faction ids and do not rename after shipping.</p><table tabindex="0"><thead><tr><th>Faction</th><th>Role</th><th>Objectives</th></tr></thead><tbody><tr><td>Forest Elves</td><td>Forest Elf</td><td>raid Empire, raid Villain, defend the Emerald Thicket</td></tr><tr><td>Empire</td><td>Palace Guard</td><td>obey the commander, defend the Imperial palace</td></tr><tr><td>Villain</td><td>Villain</td><td>command troops, attack the Imperial palace</td></tr></tbody></table><p>An objective carries a <code>kind</code> (<code>raid \\| defend \\| obey \\| command \\| attack</code>), a player-facing <code>summary</code>, and an optional <code>targetFactionId</code> (raid/attack) or <code>targetRegion</code> (defend).</p><h2 id="save-persistence-e4-2" tabindex="-1">Save persistence (E4.2) <a class="header-anchor" href="#save-persistence-e4-2" aria-label="Permalink to &quot;Save persistence (E4.2)&quot;">​</a></h2><p>The chosen player faction is persisted in the save schema as <code>playerFactionId</code> (save <strong>v3</strong>). On <strong>Continue</strong>, <code>setPlayerFaction(data.playerFactionId)</code> restores it. Old saves remain loadable: a pre-v3 save has no faction and migrates forward to <code>neutral</code>; an unrecognised persisted id is coerced to <code>neutral</code> too. See <a href="./save-system">save-system.md</a> for the schema-version history.</p>`,29)])])}const u=t(o,[["render",d]]);export{m as __pageData,u as default};
